2177   auto *BinOpTy = dyn_cast<FixedVectorType>(BinOp->getType());
2178   auto *Op0Ty = dyn_cast<FixedVectorType>(Op00->getType());
2179   auto *Op1Ty = dyn_cast<FixedVectorType>(Op10->getType());
